from langchain.agents import create_react_agent, AgentExecutor
from langchain.tools import tool
from langchain_openai import ChatOpenAI
from langchain.prompts import PromptTemplate

# Define tools the agent can use
@tool
def search_knowledge_base(query: str) -> str:
    """Search the company knowledge base for information."""
    # Simulated knowledge base search
    knowledge_base = {
        "refund policy": "Refunds are available within 30 days of purchase.",
        "shipping time": "Standard shipping takes 5-7 business days."
    }
    return knowledge_base.get(query.lower(), "Information not found.")

@tool
def calculate_refund_amount(order_id: str) -> float:
    """Calculate refund amount for a given order ID."""
    # Simulated order lookup
    orders = {"ORD-123": 99.99, "ORD-456": 149.50}
    return orders.get(order_id, 0.0)

# Initialize agent with tools
llm = ChatOpenAI(model="gpt-4", temperature=0)
tools = [search_knowledge_base, calculate_refund_amount]

prompt = PromptTemplate.from_template(
    """You are a helpful customer service agent. Use the available tools to assist users.

User question: {input}

Available tools: {tools}

Use the tools when needed. Provide a helpful response.

{agent_scratchpad}"""
)

agent = create_react_agent(llm, tools, prompt)
agent_executor = AgentExecutor(agent=agent, tools=tools, verbose=True)

# Run the agent
result = agent_executor.invoke({
    "input": "Can I get a refund for order ORD-123? What's your refund policy?"
})
print(result["output"])

