import json
import asyncio
from typing import List, Dict, Any, Callable, Optional
from dataclasses import dataclass, field
from enum import Enum
import time
import hashlib

class MCPMessageType(Enum):
    """MCP message types"""
    TOOL_LIST = "tools/list"
    TOOL_CALL = "tools/call"
    RESOURCE_LIST = "resources/list"
    RESOURCE_READ = "resources/read"
    PROMPT_LIST = "prompts/list"
    PROMPT_GET = "prompts/get"

@dataclass
class MCPTool:
    """MCP Tool definition"""
    name: str
    description: str
    parameters: Dict[str, Any]
    handler: Callable

@dataclass
class MCPResource:
    """MCP Resource definition"""
    uri: str
    name: str
    description: str
    mime_type: str
    content: Any

@dataclass
class MCPPrompt:
    """MCP Prompt template"""
    name: str
    description: str
    template: str
    arguments: List[Dict[str, str]] = field(default_factory=list)

class MCPServer:
    """MCP Server implementation - provides tools, resources, and prompts"""

    def __init__(self, name: str, version: str = "1.0.0"):
        self.name = name
        self.version = version
        self.tools: Dict[str, MCPTool] = {}
        self.resources: Dict[str, MCPResource] = {}
        self.prompts: Dict[str, MCPPrompt] = {}
        self.request_log: List[Dict] = []

    # ============ Tool Management ============

    def register_tool(self, name: str, description: str, parameters: Dict, handler: Callable):
        """Register a tool with the MCP server"""
        self.tools[name] = MCPTool(name, description, parameters, handler)
        print(f"  ✓ Registered tool: {name}")

    def list_tools(self) -> List[Dict]:
        """List available tools (tool discovery)"""
        return [
            {
                "name": tool.name,
                "description": tool.description,
                "parameters": tool.parameters,
                "server": self.name
            }
            for tool in self.tools.values()
        ]

    def call_tool(self, name: str, arguments: Dict, request_id: str = None) -> Dict:
        """Execute a tool call"""
        start_time = time.time()

        if name not in self.tools:
            return {
                "success": False,
                "error": f"Tool '{name}' not found",
                "available_tools": list(self.tools.keys())
            }

        tool = self.tools[name]
        try:
            result = tool.handler(**arguments)

            # Log request
            self.request_log.append({
                "request_id": request_id or hashlib.md5(f"{name}{time.time()}".encode()).hexdigest()[:8],
                "tool": name,
                "arguments": arguments,
                "result": str(result)[:200],
                "duration_ms": (time.time() - start_time) * 1000,
                "success": True
            })

            return {
                "success": True,
                "result": result,
                "tool": name,
                "server": self.name,
                "duration_ms": (time.time() - start_time) * 1000
            }
        except Exception as e:
            self.request_log.append({
                "request_id": request_id,
                "tool": name,
                "arguments": arguments,
                "error": str(e),
                "duration_ms": (time.time() - start_time) * 1000,
                "success": False
            })
            return {
                "success": False,
                "error": str(e),
                "tool": name
            }

    # ============ Resource Management ============

    def register_resource(self, uri: str, name: str, description: str, mime_type: str, content: Any):
        """Register a resource"""
        self.resources[uri] = MCPResource(uri, name, description, mime_type, content)
        print(f"  ✓ Registered resource: {name} ({uri})")

    def list_resources(self) -> List[Dict]:
        """List available resources"""
        return [
            {
                "uri": res.uri,
                "name": res.name,
                "description": res.description,
                "mime_type": res.mime_type
            }
            for res in self.resources.values()
        ]

    def read_resource(self, uri: str) -> Dict:
        """Read a resource"""
        if uri in self.resources:
            return {
                "success": True,
                "uri": uri,
                "content": self.resources[uri].content,
                "mime_type": self.resources[uri].mime_type
            }
        return {"success": False, "error": f"Resource '{uri}' not found"}

    # ============ Prompt Management ============

    def register_prompt(self, name: str, description: str, template: str, arguments: List[Dict[str, str]] = None):
        """Register a prompt template"""
        self.prompts[name] = MCPPrompt(name, description, template, arguments or [])
        print(f"  ✓ Registered prompt: {name}")

    def list_prompts(self) -> List[Dict]:
        """List available prompts"""
        return [
            {
                "name": prompt.name,
                "description": prompt.description,
                "arguments": prompt.arguments
            }
            for prompt in self.prompts.values()
        ]

    def get_prompt(self, name: str, arguments: Dict = None) -> Dict:
        """Get a rendered prompt"""
        if name not in self.prompts:
            return {"success": False, "error": f"Prompt '{name}' not found"}

        prompt = self.prompts[name]
        rendered = prompt.template

        if arguments:
            for key, value in arguments.items():
                rendered = rendered.replace(f"{{{{ {key} }}}}", value)

        return {
            "success": True,
            "name": name,
            "description": prompt.description,
            "rendered": rendered,
            "messages": [{"role": "user", "content": rendered}]
        }

    # ============ Server Info ============

    def get_server_info(self) -> Dict:
        """Get server information"""
        return {
            "name": self.name,
            "version": self.version,
            "tools_count": len(self.tools),
            "resources_count": len(self.resources),
            "prompts_count": len(self.prompts),
            "total_requests": len(self.request_log)
        }

    def get_request_log(self, limit: int = 10) -> List[Dict]:
        """Get recent request log"""
        return self.request_log[-limit:]


class MCPClient:
    """MCP Client for connecting to MCP servers"""

    def __init__(self):
        self.servers: Dict[str, MCPServer] = {}
        self.default_server: Optional[str] = None

    def connect(self, server: MCPServer, set_default: bool = False):
        """Connect to an MCP server"""
        self.servers[server.name] = server
        if set_default or not self.default_server:
            self.default_server = server.name
        print(f"🔌 Connected to MCP server: {server.name}")

    def disconnect(self, server_name: str):
        """Disconnect from an MCP server"""
        if server_name in self.servers:
            del self.servers[server_name]
            if self.default_server == server_name:
                self.default_server = next(iter(self.servers.keys())) if self.servers else None

    def discover_tools(self, server_name: str = None) -> List[Dict]:
        """Discover tools from a server"""
        server = self._get_server(server_name)
        if not server:
            return []
        return server.list_tools()

    def invoke_tool(self, tool_name: str, arguments: Dict, server_name: str = None) -> Dict:
        """Invoke a tool on a server"""
        server = self._get_server(server_name)
        if not server:
            return {"error": f"No server available"}

        # Auto-discover which server has this tool
        if server_name is None:
            for srv_name, srv in self.servers.items():
                if tool_name in srv.tools:
                    server = srv
                    break

        return server.call_tool(tool_name, arguments)

    def discover_resources(self, server_name: str = None) -> List[Dict]:
        """Discover resources from a server"""
        server = self._get_server(server_name)
        return server.list_resources() if server else []

    def read_resource(self, uri: str, server_name: str = None) -> Dict:
        """Read a resource"""
        server = self._get_server(server_name)
        return server.read_resource(uri) if server else {"error": "No server available"}

    def discover_prompts(self, server_name: str = None) -> List[Dict]:
        """Discover prompts from a server"""
        server = self._get_server(server_name)
        return server.list_prompts() if server else []

    def get_prompt(self, prompt_name: str, arguments: Dict = None, server_name: str = None) -> Dict:
        """Get a prompt template"""
        server = self._get_server(server_name)
        return server.get_prompt(prompt_name, arguments) if server else {"error": "No server available"}

    def _get_server(self, server_name: str = None) -> Optional[MCPServer]:
        """Get server by name or default"""
        if server_name:
            return self.servers.get(server_name)
        return self.servers.get(self.default_server) if self.default_server else None


class MCPLLMWrapper:
    """LLM wrapper that uses MCP for tool integration"""

    def __init__(self, client: MCPClient):
        self.client = client
        self.conversation_history = []

    def process_request(self, user_input: str) -> Dict:
        """Process user request using MCP tools"""
        input_lower = user_input.lower()

        # Detect intent and route to appropriate tools

        # Weather intent
        if "weather" in input_lower:
            cities = ["tokyo", "london", "new york", "paris", "berlin"]
            city = next((c for c in cities if c in input_lower), "tokyo")
            units = "fahrenheit" if "fahrenheit" in input_lower or "°f" in input_lower else "celsius"

            result = self.client.invoke_tool("get_weather", {"city": city.title(), "units": units})

            if result.get("success"):
                response = f"🌤️ {result['result']}"
            else:
                response = f"Sorry, couldn't get weather: {result.get('error', 'Unknown error')}"

        # Calculator intent
        elif any(op in input_lower for op in ["calculate", "compute", "+", "-", "*", "/", "="]):
            import re
            expr_match = re.search(r'[\d\+\-\*/\(\)\s\.]+', user_input)
            expr = expr_match.group().strip() if expr_match else "2+2"

            result = self.client.invoke_tool("calculate", {"expression": expr})

            if result.get("success"):
                response = f"🧮 {result['result']}"
            else:
                response = f"Sorry, couldn't calculate: {result.get('error', 'Invalid expression')}"

        # Search intent
        elif "search" in input_lower or "find" in input_lower:
            query = user_input.replace("search", "").replace("find", "").replace("for", "").strip()
            if not query:
                query = "artificial intelligence"

            result = self.client.invoke_tool("search", {"query": query, "limit": 3})

            if result.get("success"):
                response = f"🔍 Search results for '{query}':\n{result['result']}"
            else:
                response = f"Sorry, search failed: {result.get('error', 'Unknown error')}"

        # General response
        else:
            response = f"I can help with weather, calculations, and searches. Try asking: 'What's the weather in Tokyo?', 'Calculate 15 * 4', or 'Search for AI trends'"

        # Store conversation
        self.conversation_history.append({
            "user": user_input,
            "assistant": response,
            "timestamp": time.time()
        })

        return {
            "success": True,
            "response": response,
            "conversation_id": len(self.conversation_history)
        }

    def get_history(self) -> List[Dict]:
        """Get conversation history"""
        return self.conversation_history


def create_demo_server() -> MCPServer:
    """Create a demo MCP server with example tools"""
    server = MCPServer("demo-server", "1.0.0")

    # Weather tool
    def get_weather(city: str, units: str = "celsius"):
        weather_db = {
            "Tokyo": {"temp": 22, "condition": "Sunny", "humidity": 65},
            "London": {"temp": 15, "condition": "Cloudy", "humidity": 78},
            "New York": {"temp": 18, "condition": "Rainy", "humidity": 82},
            "Paris": {"temp": 20, "condition": "Partly Cloudy", "humidity": 70},
            "Berlin": {"temp": 17, "condition": "Overcast", "humidity": 75}
        }
        data = weather_db.get(city, {"temp": 20, "condition": "Unknown", "humidity": 70})
        if units == "fahrenheit":
            data["temp"] = (data["temp"] * 9/5) + 32
        unit_symbol = "°C" if units == "celsius" else "°F"
        return f"{city}: {data['temp']}{unit_symbol}, {data['condition']}, Humidity: {data['humidity']}%"

    server.register_tool(
        name="get_weather",
        description="Get current weather for a city",
        parameters={
            "city": {"type": "string", "description": "City name", "required": True},
            "units": {"type": "string", "enum": ["celsius", "fahrenheit"], "default": "celsius"}
        },
        handler=get_weather
    )

    # Calculator tool
    def calculate(expression: str):
        import re
        # Safe evaluation
        allowed_chars = re.match(r'^[\d\+\-\*/\(\)\s\.]+$', expression)
        if not allowed_chars:
            return "Invalid expression: only numbers and basic operators allowed"
        try:
            result = eval(expression, {"__builtins__": {}}, {})
            return f"{expression} = {result}"
        except Exception as e:
            return f"Error: {str(e)}"

    server.register_tool(
        name="calculate",
        description="Perform mathematical calculations",
        parameters={
            "expression": {"type": "string", "description": "Mathematical expression", "required": True}
        },
        handler=calculate
    )

    # Search tool
    def search(query: str, limit: int = 5):
        # Simulated search results
        mock_results = [
            f"📄 Result 1: Comprehensive guide to {query}",
            f"📄 Result 2: Latest developments in {query} - 2024",
            f"📄 Result 3: Expert insights on {query}",
            f"📄 Result 4: {query} - Best practices and examples",
            f"📄 Result 5: Community discussions about {query}"
        ]
        return "\n".join(mock_results[:limit])

    server.register_tool(
        name="search",
        description="Search for information on a topic",
        parameters={
            "query": {"type": "string", "description": "Search query", "required": True},
            "limit": {"type": "integer", "description": "Number of results", "default": 5}
        },
        handler=search
    )

    # Register a resource
    server.register_resource(
        uri="file:///config/settings.json",
        name="Application Settings",
        description="Application configuration settings",
        mime_type="application/json",
        content=json.dumps({"theme": "dark", "language": "en", "notifications": True}, indent=2)
    )

    # Register a prompt
    server.register_prompt(
        name="summarize",
        description="Summarize text with specific length",
        template="Summarize the following text in {{ length }} words:\n\n{{ text }}",
        arguments=[
            {"name": "text", "description": "Text to summarize", "required": True},
            {"name": "length", "description": "Target length in words", "required": False}
        ]
    )

    return server


